from typing import Callable, Any
import anthropic

client = anthropic.Anthropic()

class StepFailedError(Exception):
    def __init__(self, step_name: str, original: Exception):
        self.step_name = step_name
        self.original = original
        super().__init__(f"Step '{step_name}' failed: {original}")

def run_chain_safe(
    steps: list[tuple[str, Callable]],
    initial_input: Any,
    on_failure: str = "abort",  # "abort" | "skip" | "retry_once"
) -> dict:
    """
    Run a chain where each step is (name, function).
    on_failure controls behavior when a step raises.
    Returns {"status": ..., "result": ..., "failed_step": ...}
    """
    current = initial_input
    for name, step_fn in steps:
        try:
            current = step_fn(current)
        except Exception as e:
            if on_failure == "abort":
                return {"status": "failed", "failed_step": name, "error": str(e), "result": None}
            elif on_failure == "retry_once":
                try:
                    current = step_fn(current)  # one retry
                except Exception as e2:
                    return {"status": "failed", "failed_step": name, "error": str(e2), "result": None}
            elif on_failure == "skip":
                # Pass the previous step's output through unchanged
                pass

    return {"status": "complete", "result": current, "failed_step": None}

