import anthropic
import json

client = anthropic.Anthropic()

def step_classify_sentiment(text: str) -> dict:
    """Classify the sentiment of a review as positive or negative."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=20,
        system='Return JSON: {"sentiment": "positive"|"negative", "score": 0.0-1.0}',
        messages=[{"role": "user", "content": text}],
    )
    raw = resp.content[0].text.strip()
    if raw.startswith("```"):
        lines = raw.split("\n")
        raw = "\n".join(lines[1:-1] if lines[-1].strip() == "```" else lines[1:])
    try:
        return json.loads(raw)
    except json.JSONDecodeError:
        return {"sentiment": "positive", "score": 0.5}

def step_generate_thank_you(review: str) -> str:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=128,
        system="Write a brief thank-you reply to a positive customer review.",
        messages=[{"role": "user", "content": review}],
    )
    return resp.content[0].text.strip()

def step_generate_apology(review: str) -> str:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=128,
        system="Write a brief apology and resolution offer for a negative customer review.",
        messages=[{"role": "user", "content": review}],
    )
    return resp.content[0].text.strip()

def step_format_response(data: dict) -> str:
    """Format the response with metadata."""
    return (
        f"[Sentiment: {data['sentiment']} ({data['score']:.0%})]\n"
        f"{data['reply']}"
    )

def run_review_pipeline(review: str) -> str:
    """
    Branching chain:
    review -> classify -> (thank_you | apology) -> format
    """
    # Step 1: classify
    classification = step_classify_sentiment(review)

    # Step 2: conditional branch (Python code, not LLM)
    if classification["sentiment"] == "positive":
        reply = step_generate_thank_you(review)
    else:
        reply = step_generate_apology(review)

    # Step 3: format
    return step_format_response({
        "sentiment": classification["sentiment"],
        "score": classification["score"],
        "reply": reply,
    })

print(run_review_pipeline("Amazing product, exactly what I needed!"))
# [Sentiment: positive (95%)]
# Thank you so much for your kind words!...

print(run_review_pipeline("The packaging was damaged and shipping took 3 weeks."))
# [Sentiment: negative (88%)]
# We sincerely apologize for your experience...
